        /// <summary>
        /// Tries to resolve an icon in this style by its canonical string name.
        /// </summary>
        public static bool TryGet(string iconName, out HaloMaterialIcon icon)
        {
            if (string.IsNullOrWhiteSpace(iconName))
            {
                icon = default;
                return false;
            }

            return Lookup.TryGetValue(iconName.Trim(), out icon);
        }
    }
